"use client";
import { Field, FieldLabel, FieldError } from "@/components/ui/field";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useForm, Controller } from "react-hook-form";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectTrigger,
  SelectContent,
  SelectItem,
  SelectValue,
} from "@/components/ui/select";
import { Button } from "@/components/ui/button";
import { InsertProduct } from "@/lib/data/products";
import { UploadImage } from "@/lib/data/images";

const formSchema = z.object({
  title: z.string().min(5, "Title at least 5 characters long"),
  price: z.string().min(1, "Price is required"),
  description: z.string().min(10, "Description at least 10 characters long"),
  categoryId: z.string().min(1, "Category is required"),
});

type FormValues = z.infer<typeof formSchema>;

export default function ProductForm() {
  const form = useForm<FormValues>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      title: "",
      price: "",
      description: "",
      categoryId: "",
    },
  });

  async function onSubmit(values: FormValues) {
    const fileInput = document.querySelector<HTMLInputElement>("#image-input");
    const file = fileInput?.files?.[0];

    let imageUrl = "https://placehold.co/600x400/png";

    if (file) {
      const imageFormData = new FormData();
      imageFormData.append("file", file);
      const uploadedImage = await UploadImage(imageFormData);
      console.log("Uploaded image:", uploadedImage);
      imageUrl = uploadedImage.location;
    }

    const productData = {
      title: values.title,
      price: Number(values.price),
      description: values.description,
      categoryId: Number(values.categoryId),
      images: [imageUrl],
    };

    const resData = await InsertProduct(productData);
    console.log("Insert Product:", resData);
  }

  function onReset() {
    form.reset();
    form.clearErrors();
  }

  return (
    <form
      onSubmit={form.handleSubmit(onSubmit)}
      onReset={onReset}
      className="space-y-8 @container"
    >
      <div className="grid grid-cols-12 gap-4">
        <Controller
          control={form.control}
          name="title"
          render={({ field, fieldState }) => (
            <Field
              className="col-span-12 flex flex-col gap-2 items-start"
              data-invalid={fieldState.invalid}
            >
              <FieldLabel>Product Title</FieldLabel>
              <Input placeholder="Macbook Pro 16 inch" type="text" {...field} />
              {fieldState.invalid && <FieldError errors={[fieldState.error]} />}
            </Field>
          )}
        />

        <Controller
          control={form.control}
          name="price"
          render={({ field, fieldState }) => (
            <Field
              className="col-span-12 flex flex-col gap-2 items-start"
              data-invalid={fieldState.invalid}
            >
              <FieldLabel>Price</FieldLabel>
              <Input placeholder="2000" type="number" {...field} />
              {fieldState.invalid && <FieldError errors={[fieldState.error]} />}
            </Field>
          )}
        />

        <Controller
          control={form.control}
          name="description"
          render={({ field, fieldState }) => (
            <Field
              className="col-span-12 flex flex-col gap-2 items-start"
              data-invalid={fieldState.invalid}
            >
              <FieldLabel>Product Description</FieldLabel>
              <Input placeholder="Product Description here..." type="text" {...field} />
              {fieldState.invalid && <FieldError errors={[fieldState.error]} />}
            </Field>
          )}
        />

        <Controller
          control={form.control}
          name="categoryId"
          render={({ field, fieldState }) => (
            <Field
              className="col-span-12 flex flex-col gap-2 items-start"
              data-invalid={fieldState.invalid}
            >
              <FieldLabel>Category</FieldLabel>
              <Select
                value={field.value}
                name={field.name}
                onValueChange={field.onChange}
              >
                <SelectTrigger className="w-full">
                  <SelectValue placeholder="Select a category" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="1">Clothes</SelectItem>
                  <SelectItem value="2">Electronics</SelectItem>
                </SelectContent>
              </Select>
              {fieldState.invalid && <FieldError errors={[fieldState.error]} />}
            </Field>
          )}
        />

        <Field className="col-span-12 flex flex-col gap-2 items-start">
          <FieldLabel>Image Upload</FieldLabel>
          <Input id="image-input" type="file" accept="image/png,image/jpeg,image/jpg,image/gif" />
        </Field>

        <Field className="col-span-12 flex flex-col gap-2 items-start">
          <Button type="submit" variant="default" className="w-full">
            Submit
          </Button>
        </Field>

        <Field className="col-span-12 flex flex-col gap-2 items-start">
          <Button type="reset" variant="outline" className="w-full">
            Reset
          </Button>
        </Field>
      </div>
    </form>
  );
}